"use client"

import React, { useState } from "react"

export interface FilterState {
  keyword: string
  tag: string
  dateRange: string
  sort: string
}

interface ExplorePostsFilterProps {
  onFilterChange: (filter: FilterState) => void
}

export default function ExplorePostsFilter({ onFilterChange }: ExplorePostsFilterProps) {
  const [keyword, setKeyword] = useState("")
  const [tag, setTag] = useState("")
  const [dateRange, setDateRange] = useState("all")
  const [sort, setSort] = useState("recent")

  const handleChange = () => {
    onFilterChange({ keyword, tag, dateRange, sort })
  }

  return (
    <div className="flex flex-col md:flex-row items-center gap-4 mb-6">
      <input
        type="text"
        value={keyword}
        onChange={(e) => {
          setKeyword(e.target.value)
          handleChange()
        }}
        placeholder="Search posts..."
        className="border rounded px-3 py-2 w-full md:w-1/3 bg-slate-700 text-white placeholder:text-slate-400"
      />

      <select
        value={tag}
        onChange={(e) => {
          setTag(e.target.value)
          handleChange()
        }}
        className="border rounded px-3 py-2 w-full md:w-1/4 bg-slate-700 text-white"
      >
        <option value="">All Tags</option>
        <option value="Coding">Coding</option>
        <option value="TypeScript">TypeScript</option>
        <option value="Microservices">Microservices</option>
        <option value="Design">Design</option>
        <option value="Cloud">Cloud</option>
        <option value="AI">AI</option>
        <option value="VS Code">VS Code</option>
        <option value="Python">Python</option>
        <option value="Data Science">Data Science</option>
      </select>

      <select
        value={dateRange}
        onChange={(e) => {
          setDateRange(e.target.value)
          handleChange()
        }}
        className="border rounded px-3 py-2 w-full md:w-1/4 bg-slate-700 text-white"
      >
        <option value="all">All Time</option>
        <option value="today">Today</option>
        <option value="7d">Last 7 Days</option>
        <option value="month">This Month</option>
      </select>

      <select
        value={sort}
        onChange={(e) => {
          setSort(e.target.value)
          handleChange()
        }}
        className="border rounded px-3 py-2 w-full md:w-1/4 bg-slate-700 text-white"
      >
        <option value="recent">Most Recent</option>
        <option value="popular">Most Liked</option>
        <option value="comments">Most Commented</option>
      </select>
    </div>
  )
}
