"use client"

import React, { useState, useEffect } from "react"
import { useSearchParams } from "next/navigation"
import { motion } from "framer-motion"
import ExplorePostsFilter, { FilterState } from "@/components/posts/ExplorePostsFilter"
import RecentPosts from "@/components/posts/RecentPosts"
import NoPostsHolder from "@/components/posts/NoPostsHolder"
import { mockPosts } from "./mockPosts"
import type { PostCardProps } from "@/components/posts/PostCard"

export default function ExplorePostsPage() {
  const searchParams = useSearchParams()
  const initialTag = searchParams.get("tag") || ""

  const [filters, setFilters] = useState<FilterState>({
    keyword: "",
    tag: initialTag,
    dateRange: "all",
    sort: "recent",
  })

  const [filteredPosts, setFilteredPosts] = useState<PostCardProps[]>(mockPosts)

  useEffect(() => {
    let results = mockPosts

    if (filters.keyword) {
      results = results.filter((post) =>
        post.title.toLowerCase().includes(filters.keyword.toLowerCase()) ||
        post.description.toLowerCase().includes(filters.keyword.toLowerCase())
      )
    }

    if (filters.tag) {
      results = results.filter((post) => post.tags?.includes(filters.tag))
    }

    setFilteredPosts(results)
  }, [filters])

  const handleLoadMore = () => {
    console.log("Load more posts")
  }

  return (
    <main className="bg-slate-900 text-white pt-8 pb-16">
      <section className="max-w-7xl mx-auto px-4 md:px-8">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.4 }}
          className="mb-6"
        >
          <h1 className="text-3xl md:text-4xl font-bold">🔍 Explore Posts</h1>
          <p className="text-slate-400 text-sm md:text-base mt-1">
            Use the filters below to discover relevant content.
          </p>
        </motion.div>

        {/* Filters */}
        <ExplorePostsFilter onFilterChange={setFilters} />

        {/* Content */}
        {filteredPosts.length > 0 ? (
          <RecentPosts posts={filteredPosts} onLoadMore={handleLoadMore} hasMore={true} />
        ) : (
          <NoPostsHolder />
        )}
      </section>
    </main>
  )
}
